```class Solution {
    public int latestTimeCatchTheBus(int[] buses, int[] passengers, int capacity) {
        Arrays.sort(buses);
        Arrays.sort(passengers);
        int i = 0, j = 0, res = -1;
        while (i < buses.length || j < passengers.length) {
            while (i < buses.length && (j == 0 || passengers[j - 1] <= buses[i])) {
                i++;
            }
            while (j < passengers.length && (i == 0 || passengers[j] <= buses[i - 1])) {
                j++;
            }
            if (i < buses.length && j < passengers.length && j - capacity >= 0) {
                res = Math.max(res, passengers[j - capacity - 1]);
            }
        }
        return res;
    }
}```
